func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		valid     bool
	}
	for jj := 0; jj < len(oris); jj++ {
		bestCandidate := candidate{-1, 0.0, false}
		safeFallbackIdx := -1
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			savedState := dispatch.Assigns[ii]
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				oldCost := dispatch.Assigns[ii].Cost
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if !bestCandidate.valid || delta < bestCandidate.costDelta {
						bestCandidate.assignIdx = ii
						bestCandidate.costDelta = delta
						bestCandidate.valid = true
					}
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
			if safeFallbackIdx == -1 && savedState.Cost >= 0 {
				safeFallbackIdx = ii
			}
		}
		inserted := false
		if bestCandidate.valid {
			if dispatch.Assigns[bestCandidate.assignIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
				inserted = true
			}
		}
		if !inserted {
			useIdx := safeFallbackIdx
			if useIdx == -1 {
				useIdx = dispatch.AssignsLen
			}
			if useIdx < MAXASSIGNS {
				dispatch.Assigns[useIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[useIdx].GenRoute()
				if useIdx == dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

