        for tryAssignIdx := 0; tryAssignIdx < evalRange; tryAssignIdx++ {
            var baseCost float64
            if tryAssignIdx < dispatch.AssignsLen {
                baseCost = dispatch.Assigns[tryAssignIdx].Cost
