						bestAssignIdx = i
					}
				}

				assign.RemoveShip(total_ship + shipIdx)
				assign.Cost = savedStates[i]
				assign.GenRoute()
			}
		}

		if bestAssignIdx != -1 {
			target := &dispatch.Assigns[bestAssignIdx]
			target.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
