population.algorithm:
Greedy insertion with incremental cost evaluation using saved assign states, attempting each order into all existing assigns sorted by current marginal cost increase, committing the minimal non-negative delta, falling back to new empty assign if no feasible insertion exists, and renewing total cost once at end.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		bestAssignIdx := -1
		bestDelta := math.Inf(1)

		existingLimit := dispatch.AssignsLen
		for assignIdx := 0; assignIdx <= existingLimit && assignIdx < MAXASSIGNS; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]

			stateSnapshot := *assign
			costBefore := assign.Cost

			ok := assign.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if !ok {
				continue
			}
			assign.GenRoute()

			delta := assign.Cost - costBefore
			isFeasible := assign.Cost >= 0

			assign.RemoveShip(total_ship + shipIdx)
			*assign = stateSnapshot
			assign.GenRoute()

			if isFeasible && delta < bestDelta {
				bestDelta = delta
				bestAssignIdx = assignIdx
			}
		}

		if bestAssignIdx >= 0 && bestAssignIdx < MAXASSIGNS {
			chosen := &dispatch.Assigns[bestAssignIdx]
			success := chosen.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if success {
				chosen.GenRoute()
				if bestAssignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = bestAssignIdx + 1
				}
				continue
			}
		}

		fallbackIdx := dispatch.AssignsLen
		if fallbackIdx < MAXASSIGNS {
			fallback := &dispatch.Assigns[fallbackIdx]
			ok := fallback.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if ok {
				fallback.GenRoute()
				if fallback.Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					fallback.RemoveShip(total_ship + shipIdx)
					fallback.GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

