func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	usedAssignCount := dispatch.AssignsLen
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestCostDelta := 1e100
		bestSavedState := Assign{}
		id := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		for ai := 0; ai < usedAssignCount; ai++ {
			assign := &dispatch.Assigns[ai]
			oldCost := assign.Cost
			savedState := *assign
			ok := assign.AddShip(id, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				costDelta := newCost - oldCost
				if costDelta >= 0 && costDelta < bestCostDelta {
					bestCostDelta = costDelta
					bestAssignIdx = ai
					bestSavedState = savedState
				}
				assign.RemoveShip(id)
				assign.GenRoute()
			}
		}

		if bestAssignIdx != -1 {
			target := &dispatch.Assigns[bestAssignIdx]
			target.AddShip(id, ori, des)
			target.GenRoute()
		} else {
			if usedAssignCount < MAXASSIGNS {
				assign := &dispatch.Assigns[usedAssignCount]
				assign.AddShip(id, ori, des)
				assign.GenRoute()
				usedAssignCount++
			} else {
				for ai := 0; ai < usedAssignCount; ai++ {
					assign := &dispatch.Assigns[ai]
					savedState := *assign
					ok := assign.AddShip(id, ori, des)
					if ok {
						assign.GenRoute()
						if assign.Cost >= 0 {
							bestAssignIdx = ai
							bestSavedState = savedState
							break
						} else {
							assign.RemoveShip(id)
							assign.GenRoute()
						}
					}
				}
				if bestAssignIdx == -1 {
					assign := &dispatch.Assigns[usedAssignCount-1]
					assign.AddShip(id, ori, des)
					assign.GenRoute()
				} else {
					target := &dispatch.Assigns[bestAssignIdx]
					target.AddShip(id, ori, des)
					target.GenRoute()
				}
			}
		}
	}
	dispatch.AssignsLen = usedAssignCount
	dispatch.RenewnTotalCost()
	return dispatch

