population.algorithm:
Greedy insertion with rollback: try inserting each ship into every existing assign, compute marginal cost increase, pick the minimal positive feasible insertion, otherwise create a new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    for jj := 0; jj < len(oris); jj++ {
        bestIdx := -1
        bestCostDelta := 1e308
        savedStates := make([]float64, dispatch.AssignsLen)
        savedCosts := make([]float64, dispatch.AssignsLen)

        // Evaluate all existing assigns
        for ii := 0; ii < dispatch.AssignsLen; ii++ {
            savedStates[ii] = dispatch.Assigns[ii].Cost
            if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
                dispatch.Assigns[ii].GenRoute()
                if dispatch.Assigns[ii].Cost >= 0 {
                    delta := dispatch.Assigns[ii].Cost - savedStates[ii]
                    if delta < bestCostDelta {
                        bestCostDelta = delta
                        bestIdx = ii
                    }
                    savedCosts[ii] = dispatch.Assigns[ii].Cost
                }
                dispatch.Assigns[ii].RemoveShip(total_ship + jj)
                dispatch.Assigns[ii].GenRoute()
            } else {
                savedCosts[ii] = -1
            }
        }

        // Try to insert into a new empty assign if allowed
        newAssignIdx := dispatch.AssignsLen
        if newAssignIdx < MAXASSIGNS {
