func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestAssignIdx := -1
		bestCostDelta := -1.0
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		// Try inserting into existing assigns first
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assign := &dispatch.Assigns[ai]

			// Save current state
			savedCost := assign.Cost
			savedStationsLen := assign.StationsLen
			var savedStations [MAXSTATIONS]Station // assuming MAXSTATIONS constant available in context
			copy(savedStations[:assign.StationsLen], assign.Stations[:assign.StationsLen])

			// Trial insert
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					costDelta := assign.Cost - savedCost
					if bestAssignIdx == -1 || costDelta < bestCostDelta {
						bestAssignIdx = ai
						bestCostDelta = costDelta
					}
				}
			}

			// Rollback
			assign.RemoveShip(shipID)
			assign.Cost = savedCost
			assign.StationsLen = savedStationsLen
			copy(assign.Stations[:savedStationsLen], savedStations[:savedStationsLen])
			if savedCost >= 0 {
				assign.GenRoute()
			}
		}

		// Also try a potential new assign at the end (seed fallback)
		newAssignIdx := dispatch.AssignsLen
		if newAssignIdx < MAXASSIGNS {
			assign := &dispatch.Assigns[newAssignIdx]
			savedCost := assign.Cost
			savedStationsLen := assign.StationsLen
			var savedStations [MAXSTATIONS]Station
			copy(savedStations[:assign.StationsLen], assign.Stations[:assign.StationsLen])

