					if bestAssignIdx == -1 || costDelta < bestCostDelta {
						bestAssignIdx = newAssignIdx
						bestCostDelta = costDelta
					}
				}
			}

			// Always rollback the trial new assign
			assign.RemoveShip(shipID)
			assign.Cost = savedCost
			assign.StationsLen = savedStationsLen
			copy(assign.Stations[:savedStationsLen], savedStations[:savedStationsLen])
			if savedCost >= 0 {
				assign.GenRoute()
			}
		}

		// Commit the best insertion
		if bestAssignIdx != -1 {
			assign := &dispatch.Assigns[bestAssignIdx]
			assign.AddShip(shipID, ori, des)
			assign.GenRoute()
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestAssignIdx + 1
			}
		} else {
			// Fallback: force insert into a brand-new assign (should always succeed per problem guarantees)
			newAssignIdx := dispatch.AssignsLen
			if newAssignIdx < MAXASSIGNS {
				assign := &dispatch.Assigns[newAssignIdx]
				assign.AddShip(shipID, ori, des)
				assign.GenRoute()
				dispatch.AssignsLen++
			}
		}
	}

	dispatch.RenewnTotalCost()
