			savedStates[i].cost = dispatch.Assigns[i].Cost
			savedStates[i].stationCur = dispatch.Assigns[i].StationCurrent
		}
		triedAllExisting := false
		for attempt := 0; attempt < 2; attempt++ {
			startIdx := 0
			endIdx := dispatch.AssignsLen
			if attempt == 1 {
				if triedAllExisting {
					break
				}
				startIdx = dispatch.AssignsLen
				endIdx = dispatch.AssignsLen + 1
			}
			for ii := startIdx; ii < endIdx; ii++ {
				if attempt == 1 && ii >= MAXASSIGNS {
					continue
				}
				oldCost := dispatch.Assigns[ii].Cost
				ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[ii].GenRoute()
					newCost := dispatch.Assigns[ii].Cost
					if newCost >= 0 {
						delta := newCost - oldCost
						if delta < bestCostDelta {
