func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	shipCount := len(oris)
	for sIdx := 0; sIdx < shipCount; sIdx++ {
		bestAssignIdx := -1
		bestDeltaCost := 1e18
		originalCosts := make([]float64, dispatch.AssignsLen+1)
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
		}
		for aIdx := 0; aIdx <= dispatch.AssignsLen; aIdx++ {
			if aIdx == MAXASSIGNS {
				continue
			}
			var ok bool
			if aIdx < dispatch.AssignsLen {
				ok = dispatch.Assigns[aIdx].AddShip(total_ship+sIdx, oris[sIdx], dess[sIdx])
			} else {
				ok = false
			}
			if ok {
				oldCost := originalCosts[aIdx]
				dispatch.Assigns[aIdx].GenRoute()
				newCost := dispatch.Assigns[aIdx].Cost
				delta := newCost - oldCost
				if delta < bestDeltaCost && newCost >= 0 {
					bestDeltaCost = delta
					bestAssignIdx = aIdx
				}
				dispatch.Assigns[aIdx].RemoveShip(total_ship + sIdx)
				dispatch.Assigns[aIdx].Cost = originalCosts[aIdx]
				dispatch.Assigns[aIdx].GenRoute()
			} else if aIdx == dispatch.AssignsLen {
				fallbackIdx := dispatch.AssignsLen
				if fallbackIdx < MAXASSIGNS {
					okFallback := dispatch.Assigns[fallbackIdx].AddShip(total_ship+sIdx, oris[sIdx], dess[sIdx])
					if okFallback {
						dispatch.Assigns[fallbackIdx].GenRoute()
						if dispatch.Assigns[fallbackIdx].Cost >= 0 {
							bestAssignIdx = fallbackIdx
							bestDeltaCost = dispatch.Assigns[fallbackIdx].Cost
						}
						dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + sIdx)
						dispatch.Assigns[fallbackIdx].Cost = 0
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}
		if bestAssignIdx >= 0 && bestAssignIdx < dispatch.AssignsLen {
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+sIdx, oris[sIdx], dess[sIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
		} else if bestAssignIdx == dispatch.AssignsLen && bestAssignIdx < MAXASSIGNS {
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+sIdx, oris[sIdx], dess[sIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			dispatch.AssignsLen++
		} else {
			fallbackNewIdx := dispatch.AssignsLen
