				added := dispatch.Assigns[fallbackNewIdx].AddShip(total_ship+sIdx, oris[sIdx], dess[sIdx])
				if added {
					dispatch.Assigns[fallbackNewIdx].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

